use std::collections::HashSet;

struct DSU {
    parent: Vec<usize>,
    rank: Vec<usize>,
}

impl DSU {
    fn new(n: usize) -> Self {
        let parent = (0..n).map(|x| x).collect::<Vec<_>>();
        let rank = vec![1; n];
        DSU { parent, rank }
    }

    fn find(&mut self, x: usize) -> usize {
        if self.parent[x] != x {
            self.parent[x] = self.find(self.parent[x]);
        }
        self.parent[x]
    }

    fn union(&mut self, x: usize, y: usize) {
        let x_root = self.find(x);
        let y_root = self.find(y);
        if x_root == y_root {
            return;
        }
        if self.rank[x_root] < self.rank[y_root] {
            self.parent[x_root] = y_root;
        } else {
            self.parent[y_root] = x_root;
            if self.rank[x_root] == self.rank[y_root] {
                self.rank[x_root] += 1;
            }
        }
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    let n = n as usize;
    let mut dsu = DSU::new(n);
    for edge in &edges {
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        dsu.union(u, v);
    }
    let mut roots = HashSet::new();
    for i in 0..n {
        roots.insert(dsu.find(i));
    }
    let initial_components = roots.len();
    if initial_components >= k {
        return 0;
    }

    let mut low = 0;
    let mut high = 0;
    if !edges.is_empty() {
        high = edges.iter().map(|e| e[2]).max().unwrap() as i64;
    }

    let mut answer = high;

    while low <= high {
        let mid = (low + high) / 2;
        let mut dsu = DSU::new(n);
        for edge in &edges {
            let time = edge[2];
            if time > mid {
                let u = edge[0] as usize;
                let v = edge[1] as usize;
                dsu.union(u, v);
            }
        }
        let mut roots = HashSet::new();
        for i in 0..n {
            roots.insert(dsu.find(i));
        }
        let current_components = roots.len();
        if current_components >= k {
            answer = mid;
            high = mid - 1;
        } else {
            low = mid + 1;
        }
    }

    answer
