use std::collections::VecDeque;

fn solve(n: i64, edges: Vec<Vec<i64>>, k: i64) -> i64 {
    if k == n {
        return 0;
    }
    let max_time = if edges.is_empty() {
        0
    } else {
        *edges.iter().map(|e| e[2]).max().unwrap()
    };
    let mut low = 0;
    let mut high = max_time;
    while low < high {
        let mid = (low + high) / 2;
        let count = count_components(n, &edges, mid);
        if count >= k {
            high = mid;
        } else {
            low = mid + 1;
        }
    }
    low
}

fn count_components(n: i64, edges: &Vec<Vec<i64>>, t: i64) -> i64 {
    let mut adj = vec![vec![]; n as usize];
    for e in edges.iter() {
        if e[2] > t {
            let u = e[0] as usize;
            let v = e[1] as usize;
            adj[u].push(v);
            adj[v].push(u);
        }
    }
    let mut visited = vec![false; n as usize];
    let mut count = 0;
    for i in 0..n {
        if !visited[i as usize] {
            count += 1;
            let mut queue = VecDeque::new();
            queue.push_back(i as usize);
            visited[i as usize] = true;
            while let Some(node) = queue.pop_front() {
                for neighbor in &adj[node] {
                    if !visited[*neighbor] {
                        visited[*neighbor] = true;
                        queue.push_back(*neighbor);
                    }
                }
            }
        }
    }
    count
}
